func:
// Boot-time defaults — overwritten on first /was/rl/reset call.
flow.set('Z1Level', 25);
flow.set('Z2Level', 25);
flow.set('Z1Light',  false);
flow.set('Z2Light',  false);
flow.set('Z1Blinds', false);
flow.set('Z2Blinds', false);
// Effective (delayed) blind apertures + per-blind transition countdowns.
flow.set('Z1BlindsEff', false);
flow.set('Z2BlindsEff', false);
flow.set('Z1BlindsRem', null);
flow.set('Z2BlindsRem', null);
flow.set('Sunshine', 0);
flow.set('SunshinePinned', false);
flow.set('Tick', 0);
flow.set('TotalEnergyCost', 0);
flow.set('EnergyCost', 0);
flow.set('Hour', 0);
return msg;

// Status returns the COMMANDED blind flags (Q-state parity with Lab 2), the
// DELAYED zone levels, and the monotonic Tick clock (for delay measurement).
msg.payload = {
    Z1Level:         flow.get('Z1Level'),
    Z2Level:         flow.get('Z2Level'),
    Z1Light:         flow.get('Z1Light'),
    Z2Light:         flow.get('Z2Light'),
    Z1Blinds:        flow.get('Z1Blinds'),
    Z2Blinds:        flow.get('Z2Blinds'),
    Sunshine:        flow.get('Sunshine'),
    Tick:            flow.get('Tick'),
    EnergyCost:      flow.get('EnergyCost'),
    TotalEnergyCost: flow.get('TotalEnergyCost'),
    Hour:            flow.get('Hour')
};
return msg;

// Action endpoint: mutate actuator FLAGS only (the COMMANDED state). NO physics
// here. Lamp flags take effect on the next env tick; blind flags begin a
// delayed transition (handled in the env tick via the effective-state
// countdown).
if (msg.payload) {
    if (msg.payload.Z1Light  !== undefined) flow.set('Z1Light',  !!msg.payload.Z1Light);
    if (msg.payload.Z2Light  !== undefined) flow.set('Z2Light',  !!msg.payload.Z2Light);
    if (msg.payload.Z1Blinds !== undefined) flow.set('Z1Blinds', !!msg.payload.Z1Blinds);
    if (msg.payload.Z2Blinds !== undefined) flow.set('Z2Blinds', !!msg.payload.Z2Blinds);
}
msg.payload = { status: 'ok' };
return msg;

// ──────────────────────────────────────────────────────────────────
// Lab_2_Slow physics — DETERMINISTIC, pure function of flow state, with a
// TEMPORAL response delay on the motorized blinds (Phase 3 process dynamics).
//
//   Lamp: INSTANT. Z*Level reflects Z*Light immediately.
//   Blind: the EFFECTIVE aperture Z*BlindsEff lags the COMMANDED Z*Blinds flag
//          by BLIND_DELAY_TICKS env ticks. Physics uses the EFFECTIVE aperture.
//
//   Z1Level = 25 + (Z1Light ? 400 : 0) + (Z1BlindsEff ? 0.50 * sun : 0)
//   Z2Level = 25 + (Z2Light ? 400 : 0) + (Z2BlindsEff ? 0.50 * sun : 0)
//
// NO Math.random — dynamics are a pure function of (Z*Light, Z*Blinds, Sunshine)
// and the prior effective state.
// ──────────────────────────────────────────────────────────────────
var DELAY = 12;  // BLIND_DELAY_TICKS (≈ 60 s at seconds_per_tick = 5)

// Monotonic simulator clock — read by the DynamicsLearner to measure delay.
var tick = (flow.get('Tick') || 0) + 1;
flow.set('Tick', tick);

var sun = flow.get('Sunshine')  || 0;
var z1l = flow.get('Z1Light')   || false;
var z2l = flow.get('Z2Light')   || false;

// Motorized blind dynamics: COMMANDED flag → EFFECTIVE aperture with lag.
function stepBlind(cmdKey, effKey, remKey) {
    var cmd = flow.get(cmdKey) || false;
    var eff = flow.get(effKey) || false;
    var rem = flow.get(remKey);
    if (cmd !== eff) {
        if (rem === undefined || rem === null) rem = DELAY;
        rem = rem - 1;
        if (rem <= 0) { eff = cmd; rem = null; }
    } else {
        rem = null;
    }
    flow.set(effKey, eff);
    flow.set(remKey, rem);
    return eff;
}
var z1bEff = stepBlind('Z1Blinds', 'Z1BlindsEff', 'Z1BlindsRem');
var z2bEff = stepBlind('Z2Blinds', 'Z2BlindsEff', 'Z2BlindsRem');

var z1 = 25
       + (z1l    ? 400        : 0)
       + (z1bEff ? 0.50 * sun : 0);

var z2 = 25
       + (z2l    ? 400        : 0)
       + (z2bEff ? 0.50 * sun : 0);

flow.set('Z1Level', z1);
flow.set('Z2Level', z2);

// Per-tick energy accounting. Lamps: 1 unit/tick each. Blinds: passive (0).
var perTick = (z1l ? 1 : 0) + (z2l ? 1 : 0);
flow.set('TotalEnergyCost', (flow.get('TotalEnergyCost') || 0) + perTick);
flow.set('EnergyCost',      perTick);

// Informational hour counter.
var hr = (flow.get('Hour') || 0) + 0.1;
if (hr >= 24) hr = 0;
flow.set('Hour', hr);

return null;

// Randomise state for a new training episode. PRNG is INTENTIONAL here:
// episode-start sampling (not physics). The blind starts SETTLED (effective ==
// commanded, countdown cleared) and Tick is reset to 0.
var levels   = [25, 75, 150, 500];
var sunRanks = [0, 100, 400, 900];
var z1b = Math.random() < 0.5;
var z2b = Math.random() < 0.5;
flow.set('Z1Level',  levels[Math.floor(Math.random() * levels.length)]);
flow.set('Z2Level',  levels[Math.floor(Math.random() * levels.length)]);
flow.set('Z1Light',  Math.random() < 0.5);
flow.set('Z2Light',  Math.random() < 0.5);
flow.set('Z1Blinds', z1b);
flow.set('Z2Blinds', z2b);
flow.set('Z1BlindsEff', z1b);   // start settled
flow.set('Z2BlindsEff', z2b);
flow.set('Z1BlindsRem', null);
flow.set('Z2BlindsRem', null);
flow.set('Sunshine', sunRanks[Math.floor(Math.random() * sunRanks.length)]);
flow.set('SunshinePinned', true);  // sun is FIXED per episode
flow.set('Tick', 0);
flow.set('TotalEnergyCost', 0);
flow.set('EnergyCost', 0);
msg.payload = { reset: true };
return msg;

// Pin simulator to an exact deterministic state for benchmarking. Any pinned
// blind is SETTLED immediately (effective == commanded, countdown cleared) so
// each scenario starts at steady state. Tick is reset to 0 so a probe can
// measure response delay from a clean baseline.
var p = msg.payload || {};
if (p.Z1Level  !== undefined) flow.set('Z1Level',  p.Z1Level);
if (p.Z2Level  !== undefined) flow.set('Z2Level',  p.Z2Level);
if (p.Z1Light  !== undefined) flow.set('Z1Light',  !!p.Z1Light);
if (p.Z2Light  !== undefined) flow.set('Z2Light',  !!p.Z2Light);
if (p.Z1Blinds !== undefined) { flow.set('Z1Blinds', !!p.Z1Blinds); flow.set('Z1BlindsEff', !!p.Z1Blinds); flow.set('Z1BlindsRem', null); }
if (p.Z2Blinds !== undefined) { flow.set('Z2Blinds', !!p.Z2Blinds); flow.set('Z2BlindsEff', !!p.Z2Blinds); flow.set('Z2BlindsRem', null); }
if (p.Sunshine !== undefined) flow.set('Sunshine', p.Sunshine);
flow.set('SunshinePinned', true);
flow.set('Tick', 0);
flow.set('TotalEnergyCost', 0);
flow.set('EnergyCost', 0);
msg.payload = { status: 'ok' };
return msg;

var started = flow.get('__startedAt');
if (!started) { started = Date.now(); flow.set('__startedAt', started); }
msg.payload = {
    status: 'ok',
    tab: 'lab2slow_tab',
    uptime_ms: Date.now() - started,
    endpoints: { status: true, action: true, reset: true, setState: true }
};
msg.statusCode = 200;
msg.headers = { 'Content-Type': 'application/json' };
return msg;
